import React, { useEffect, useMemo, useState } from 'react';
import { toast } from 'react-toastify';
import { adminApi } from '../api/authApi';
import { useAuth } from '../context/AuthContext';
import Card from '../components/Card';
import { CheckCircle2, Shield, Users } from 'lucide-react';

const AdminDashboard = () => {
  const { user } = useAuth();
  const [loading, setLoading] = useState(true);
  const [users, setUsers] = useState([]);
  const [roleFilter, setRoleFilter] = useState('all');

  const params = useMemo(() => {
    if (roleFilter === 'all') return {};
    return { role: roleFilter };
  }, [roleFilter]);

  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await adminApi.getUsers(params);
      setUsers(response.data?.data || []);
    } catch (error) {
      toast.error('Failed to fetch users');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchUsers();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [roleFilter]);

  const handleVerifyAlumni = async (alumniId) => {
    try {
      await adminApi.verifyAlumni(alumniId, true);
      toast.success('Alumni verified successfully');
      await fetchUsers();
    } catch (error) {
      toast.error(error?.response?.data?.message || 'Failed to verify alumni');
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 py-8">
      <div className="container mx-auto px-4">
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2 flex items-center gap-3">
            <Shield className="h-8 w-8 text-blue-700" /> Admin Dashboard
          </h1>
          <p className="text-gray-600">
            Welcome{user?.name ? `, ${user.name}` : ''}. Manage and verify accounts.
          </p>
        </div>

        <Card className="mb-6 p-4">
          <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
            <div>
              <label className="text-sm font-medium text-gray-700">Filter by role</label>
              <select
                className="form-select mt-2"
                value={roleFilter}
                onChange={(e) => setRoleFilter(e.target.value)}
              >
                <option value="all">All users</option>
                <option value="alumni">Alumni</option>
                <option value="currentStudent">Current Students</option>
                <option value="admin">Admins</option>
              </select>
            </div>
            <div className="text-sm text-gray-600 flex items-center gap-2">
              <Users className="h-4 w-4" />
              Showing {users.length} user(s)
            </div>
          </div>
        </Card>

        {loading ? (
          <div className="min-h-[240px] flex items-center justify-center">
            <div className="animate-spin rounded-full h-16 w-16 border-b-2 border-blue-600" />
          </div>
        ) : (
          <Card>
            <div className="overflow-x-auto">
              <table className="min-w-full text-left">
                <thead>
                  <tr className="border-b">
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Name</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Email</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Role</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Phone</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Location</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Verification</th>
                    <th className="py-3 px-4 text-sm font-semibold text-gray-700">Action</th>
                  </tr>
                </thead>
                <tbody>
                  {users.map((u) => (
                    <tr key={u._id} className="border-b">
                      <td className="py-3 px-4 text-sm text-gray-900 font-medium">{u.name}</td>
                      <td className="py-3 px-4 text-sm text-gray-600">{u.email}</td>
                      <td className="py-3 px-4 text-sm text-gray-600">{u.role}</td>
                      <td className="py-3 px-4 text-sm text-gray-600">{u.phone || '-'}</td>
                      <td className="py-3 px-4 text-sm text-gray-600">{u.location || '-'}</td>
                      <td className="py-3 px-4 text-sm text-gray-600">
                        {u.role === 'alumni' ? (u.isVerified ? 'Verified' : 'Not verified') : '-'}
                      </td>
                      <td className="py-3 px-4 text-sm">
                        {u.role === 'alumni' && !u.isVerified ? (
                          <button
                            className="btn btn-primary"
                            onClick={() => handleVerifyAlumni(u._id)}
                          >
                            <CheckCircle2 className="h-4 w-4 mr-2" />
                            Verify
                          </button>
                        ) : (
                          <span className="text-gray-500">—</span>
                        )}
                      </td>
                    </tr>
                  ))}
                  {users.length === 0 && (
                    <tr>
                      <td colSpan={7} className="py-8 text-center text-gray-500">
                        No users found for the selected role.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </Card>
        )}
      </div>
    </div>
  );
};

export default AdminDashboard;
